fun valid(b: Array<CharArray>, r: Int, c: Int, ch: Char): Boolean { for (i in 0 until 9) if (b[r][i] == ch || b[i][c] == ch) return false; val br = (r / 3) * 3; val bc = (c / 3) * 3; for (i in br until br + 3) for (j in bc until bc + 3) if (b[i][j] == ch) return false; return true }
fun solve(b: Array<CharArray>): Boolean { for (r in 0 until 9) for (c in 0 until 9) if (b[r][c] == '.') { for (ch in '1'..'9') if (valid(b, r, c, ch)) { b[r][c] = ch; if (solve(b)) return true; b[r][c] = '.' }; return false }; return true }
fun main(){ val lines=generateSequence(::readLine).toList(); if(lines.isEmpty()) return; var idx=0; val t=lines[idx++].trim().toInt(); val out=mutableListOf<String>(); repeat(t){ val b=Array(9){ lines[idx++].toCharArray() }; solve(b); out.addAll(b.map { String(it) }) }; print(out.joinToString("\n")) }
